    11→export function validateRepository(provider: string, repo: string): string | null {
    12→  const trimmed = repo.trim();
    13→  if (!trimmed) return null;
    14→  if (provider === "github" && /^(https?:\/\/)?github\.com\//i.test(trimmed)) {
    15→    return "Use owner/repo format (e.g. ethereum/go-ethereum), not a full URL";
    16→  }
    17→  if (provider === "dockerhub" && /^(https?:\/\/)?hub\.docker\.com\//i.test(trimmed)) {
    18→    return "Use owner/image format (e.g. library/nginx), not a full URL";
    19→  }
    20→  if (provider === "ecr-public" && /^(https?:\/\/)?(gallery\.ecr\.aws|public\.ecr\.aws)\//i.test(trimmed)) {
    21→    return "Use alias/repo format (e.g. i6b2w2n6/op-node), not a full URL";
    22→  }
    23→  if (provider === "gitlab" && /^(https?:\/\/)?gitlab\.com\//i.test(trimmed)) {
    24→    return "Use owner/repo format (e.g. inkscape/inkscape), not a full URL";
    25→  }
    26→  if (/^https?:\/\//.test(trimmed)) {
    27→    return "Use owner/repo format, not a full URL";
    28→  }
    29→  return null;
    30→}
