    50→// discordUrgencyColor returns a Discord embed color based on urgency level.
    51→func discordUrgencyColor(level string) int {
    52→	switch strings.ToUpper(strings.TrimSpace(level)) {
    53→	case "CRITICAL":
    54→		return 0x111113 // near-black
    55→	case "HIGH":
    56→		return 0xDC2626 // red
    57→	case "MEDIUM":
    58→		return 0xD97706 // amber
    59→	case "LOW":
    60→		return 0x16A34A // green
    61→	default:
    62→		return 0x5865F2 // Discord blurple
    63→	}
    64→}
    65→
    66→// buildSemanticEmbed builds a compact Discord embed from a SemanticReport.
    67→func buildSemanticEmbed(title string, version string, report *models.SemanticReport, msg Notification) discordEmbed {
    68→	// Resolve urgency from new field or backward-compat risk_level
    69→	urgency := report.Urgency
    70→	if urgency == "" {
    71→		urgency = report.RiskLevel
    72→	}
    73→	urgencyReason := report.UrgencyReason
    74→	if urgencyReason == "" {
    75→		urgencyReason = report.RiskReason
    76→	}
    77→
    78→	var descParts []string
    79→
    80→	// Urgency badge
    81→	if urgency != "" {
    82→		descParts = append(descParts, fmt.Sprintf("%s **%s Urgency**", urgencyEmoji(urgency), urgency))
    83→	}
    84→
    85→	// Urgency reason (only for Critical/High)
    86→	upperUrgency := strings.ToUpper(strings.TrimSpace(urgency))
    87→	if (upperUrgency == "CRITICAL" || upperUrgency == "HIGH") && urgencyReason != "" {
    88→		descParts = append(descParts, urgencyReason)
    89→	}
    90→
    91→	// Changelog summary
    92→	summary := report.ChangelogSummary
    93→	if summary == "" {
    94→		summary = report.Summary
    95→	}
    96→	if summary != "" {
    97→		descParts = append(descParts, summary)
    98→	}
    99→
   100→	// First download command
   101→	if len(report.DownloadCommands) > 0 {
   102→		descParts = append(descParts, fmt.Sprintf("`%s`", report.DownloadCommands[0]))
   103→	}
   104→
   105→	// Links
   106→	var linkParts []string
   107→	if msg.SourceURL != "" {
   108→		linkParts = append(linkParts, fmt.Sprintf("[View on %s](%s)", ProviderLabel(msg.Provider), msg.SourceURL))
   109→	}
   110→	if msg.ReleaseURL != "" {
   111→		linkParts = append(linkParts, fmt.Sprintf("[View in Changelogue](%s)", msg.ReleaseURL))
   112→	}
   113→	if len(linkParts) > 0 {
   114→		descParts = append(descParts, strings.Join(linkParts, "  •  "))
   115→	}
   116→
   117→	description := strings.Join(descParts, "\n\n")
   118→	if len(description) > discordEmbedDescriptionLimit {
   119→		description = description[:discordEmbedDescriptionLimit-3] + "..."
   120→	}
   121→
   122→	// Footer with source info
   123→	var footerText string
   124→	if msg.Provider != "" && msg.Repository != "" {
   125→		footerText = fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository)
   126→	}
   127→
   128→	embed := discordEmbed{
   129→		Title:       title,
   130→		Description: description,
   131→		Color:       discordUrgencyColor(urgency),
   132→	}
   133→	if footerText != "" {
   134→		embed.Footer = &discordEmbedFooter{Text: footerText}
   135→	}
   136→	return embed
   137→}
