   139→func (s *DiscordSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   140→	var cfg discordConfig
   141→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   142→		return fmt.Errorf("parse discord config: %w", err)
   143→	}
   144→
   145→	var embed discordEmbed
   146→	var report models.SemanticReport
   147→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   148→		embed = buildSemanticEmbed(msg.Title, msg.Version, &report, msg)
   149→	} else {
   150→		// Fallback: extract known fields from raw data for a readable message.
   151→		var descParts []string
   152→		if fields, ok := parseRawBody(msg.Body); ok && fields.Changelog != "" {
   153→			// Convert changelog markdown to ASCII and wrap in a code
   154→			// block. Discord auto-collapses long code blocks.
   155→			asciiChangelog := markdownToASCII(fields.Changelog)
   156→			descParts = append(descParts, fmt.Sprintf("```%s```", asciiChangelog))
   157→		}
   158→
   159→		// Add links
   160→		var linkParts []string
   161→		if msg.SourceURL != "" {
   162→			linkParts = append(linkParts, fmt.Sprintf("[View on %s](%s)", ProviderLabel(msg.Provider), msg.SourceURL))
   163→		}
   164→		if msg.ReleaseURL != "" {
   165→			linkParts = append(linkParts, fmt.Sprintf("[View in Changelogue](%s)", msg.ReleaseURL))
   166→		}
   167→		if len(linkParts) > 0 {
   168→			descParts = append(descParts, strings.Join(linkParts, "  •  "))
   169→		}
   170→
   171→		description := strings.Join(descParts, "\n\n")
   172→		if len(description) > discordEmbedDescriptionLimit {
   173→			description = description[:discordEmbedDescriptionLimit-3] + "..."
   174→		}
   175→
   176→		embed = discordEmbed{
   177→			Title:       msg.Title,
   178→			Description: description,
   179→			Color:       0x5865F2,
   180→			Fields: []discordEmbedField{
   181→				{Name: "Version", Value: msg.Version, Inline: true},
   182→			},
   183→		}
   184→		if msg.Provider != "" && msg.Repository != "" {
   185→			embed.Footer = &discordEmbedFooter{Text: fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository)}
   186→		}
   187→	}
   188→
   189→	payload := discordPayload{Embeds: []discordEmbed{embed}}
   190→
   191→	body, err := json.Marshal(payload)
   192→	if err != nil {
   193→		return fmt.Errorf("marshal discord payload: %w", err)
   194→	}
   195→
   196→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   197→	if err != nil {
   198→		return fmt.Errorf("create request: %w", err)
   199→	}
   200→	req.Header.Set("Content-Type", "application/json")
   201→
   202→	client := s.Client
   203→	if client == nil {
   204→		client = http.DefaultClient
   205→	}
   206→
   207→	resp, err := client.Do(req)
   208→	if err != nil {
   209→		return fmt.Errorf("send discord notification: %w", err)
   210→	}
   211→	defer resp.Body.Close()
   212→
   213→	if resp.StatusCode >= 400 {
   214→		return fmt.Errorf("discord returned status %d", resp.StatusCode)
   215→	}
   216→	return nil
   217→}
