    74→func (s *EmailSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
    75→	var cfg emailConfig
    76→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
    77→		return fmt.Errorf("parse email config: %w", err)
    78→	}
    79→
    80→	if len(cfg.ToAddresses) == 0 {
    81→		return fmt.Errorf("email config: to_addresses is empty")
    82→	}
    83→
    84→	data := s.buildEmailData(msg)
    85→
    86→	// Render HTML body.
    87→	var htmlBuf bytes.Buffer
    88→	if err := emailTmpl.Execute(&htmlBuf, data); err != nil {
    89→		return fmt.Errorf("render email template: %w", err)
    90→	}
    91→
    92→	// Build plain text body.
    93→	plainText := s.buildPlainText(data)
    94→
    95→	// Assemble multipart/alternative MIME message.
    96→	var msgBuf bytes.Buffer
    97→	msgBuf.WriteString(fmt.Sprintf("From: %s\r\n", sanitizeHeader(cfg.FromAddress)))
    98→	msgBuf.WriteString(fmt.Sprintf("To: %s\r\n", sanitizeHeader(strings.Join(cfg.ToAddresses, ", "))))
    99→	msgBuf.WriteString(fmt.Sprintf("Subject: %s\r\n", sanitizeHeader(data.Subject)))
   100→	msgBuf.WriteString("MIME-Version: 1.0\r\n")
   101→
   102→	mw := multipart.NewWriter(&msgBuf)
   103→	msgBuf.WriteString(fmt.Sprintf("Content-Type: multipart/alternative; boundary=%s\r\n\r\n", mw.Boundary()))
   104→
   105→	// Plain text part.
   106→	textHeader := make(textproto.MIMEHeader)
   107→	textHeader.Set("Content-Type", "text/plain; charset=utf-8")
   108→	pw, err := mw.CreatePart(textHeader)
   109→	if err != nil {
   110→		return fmt.Errorf("create text part: %w", err)
   111→	}
   112→	pw.Write([]byte(plainText))
   113→
   114→	// HTML part.
   115→	htmlHeader := make(textproto.MIMEHeader)
   116→	htmlHeader.Set("Content-Type", "text/html; charset=utf-8")
   117→	hw, err := mw.CreatePart(htmlHeader)
   118→	if err != nil {
   119→		return fmt.Errorf("create html part: %w", err)
   120→	}
   121→	hw.Write(htmlBuf.Bytes())
   122→
   123→	mw.Close()
   124→
   125→	// Send via SMTP.
   126→	addr := fmt.Sprintf("%s:%d", cfg.SMTPHost, cfg.SMTPPort)
   127→	dialer := &net.Dialer{Timeout: 10 * time.Second}
   128→
   129→	var client *smtp.Client
   130→	if cfg.SMTPPort == 465 {
   131→		// Direct TLS (port 465).
   132→		conn, err := tls.DialWithDialer(
   133→			dialer,
   134→			"tcp", addr,
   135→			&tls.Config{ServerName: cfg.SMTPHost},
   136→		)
   137→		if err != nil {
   138→			return fmt.Errorf("tls dial: %w", err)
   139→		}
   140→		client, err = smtp.NewClient(conn, cfg.SMTPHost)
   141→		if err != nil {
   142→			conn.Close()
   143→			return fmt.Errorf("smtp client over tls: %w", err)
   144→		}
   145→	} else {
   146→		// STARTTLS (port 587 or other).
   147→		conn, err := dialer.DialContext(ctx, "tcp", addr)
   148→		if err != nil {
   149→			return fmt.Errorf("smtp dial: %w", err)
   150→		}
   151→		client, err = smtp.NewClient(conn, cfg.SMTPHost)
   152→		if err != nil {
   153→			conn.Close()
   154→			return fmt.Errorf("smtp client: %w", err)
   155→		}
   156→		if err := client.Hello("localhost"); err != nil {
   157→			client.Close()
   158→			return fmt.Errorf("smtp hello: %w", err)
   159→		}
   160→		// Only attempt STARTTLS if the server supports it.
   161→		if ok, _ := client.Extension("STARTTLS"); ok {
   162→			if err := client.StartTLS(&tls.Config{ServerName: cfg.SMTPHost}); err != nil {
   163→				client.Close()
   164→				return fmt.Errorf("smtp starttls: %w", err)
   165→			}
   166→		}
   167→	}
   168→	defer client.Close()
   169→
   170→	// Only authenticate when credentials are provided. This allows
   171→	// unauthenticated local servers like MailHog/MailPit for testing.
   172→	if cfg.Username != "" || cfg.Password != "" {
   173→		auth := smtp.PlainAuth("", cfg.Username, cfg.Password, cfg.SMTPHost)
   174→		if err := client.Auth(auth); err != nil {
   175→			return fmt.Errorf("smtp auth: %w", err)
   176→		}
   177→	}
   178→
   179→	if err := client.Mail(cfg.FromAddress); err != nil {
   180→		return fmt.Errorf("smtp mail from: %w", err)
   181→	}
   182→	for _, to := range cfg.ToAddresses {
   183→		if err := client.Rcpt(to); err != nil {
   184→			return fmt.Errorf("smtp rcpt to %s: %w", to, err)
   185→		}
   186→	}
   187→
   188→	wc, err := client.Data()
   189→	if err != nil {
   190→		return fmt.Errorf("smtp data: %w", err)
   191→	}
   192→	if _, err := wc.Write(msgBuf.Bytes()); err != nil {
   193→		wc.Close()
   194→		return fmt.Errorf("smtp write: %w", err)
   195→	}
   196→	if err := wc.Close(); err != nil {
   197→		return fmt.Errorf("smtp data close: %w", err)
   198→	}
   199→
   200→	if err := client.Quit(); err != nil {
   201→		slog.Warn("smtp quit error (email already sent)", "err", err)
   202→	}
   203→	return nil
   204→}
